export const CATEGORIES = ['Todos', 'Bilionários', 'Empreendedorismo', 'Disciplina', 'Filosofia', 'Estratégia', 'Retórica', 'Oratória'];

export const getDailyQuote = (): Quote => {
  const today = new Date();
  const dayOfYear = Math.floor(
    (today.getTime() - new Date(today.getFullYear(), 0, 0).getTime()) / 86400000
  );
  return QUOTES[dayOfYear % QUOTES.length];
};

export const getRandomQuote = (excludeId?: string): Quote => {
  const filtered = excludeId ? QUOTES.filter((q) => q.id !== excludeId) : QUOTES;
  return filtered[Math.floor(Math.random() * filtered.length)];
};

export const getQuotesByCategory = (category: string): Quote[] => {
  if (category === 'Todos') return QUOTES;
  return QUOTES.filter((q) => q.category === category);
};
